const d = $input.first().json;
const excerptText = d.excerpts.map((e, i) => `  [${i+1}] "${e}"`).join('\n');
const system = `You are a JTBD (Jobs-to-be-Done) analyst. You extract the functional, emotional, and social jobs users are trying to get done from raw interview quotes and research notes. You follow the JTBD framework: jobs are stable, goals-oriented, and context-independent. Return ONLY valid JSON.`;
const user = `Extract Jobs-to-be-Done from these research excerpts.
Source: ${d.source}
Persona context: ${d.persona}

Excerpts:
${excerptText}

Return JSON:
{
  "functional_jobs": [
    { "job": "string — When [situation], I want to [motivation], so I can [outcome]", "frequency": "daily|weekly|occasional", "evidence_indexes": [1, 3], "current_solution": "string", "underserved": true }
  ],
  "emotional_jobs": [
    { "job": "string — Feel [emotion] when/after [trigger]", "valence": "positive|negative", "evidence_indexes": [2], "product_implication": "string" }
  ],
  "social_jobs": [
    { "job": "string — Be perceived as [attribute] by [audience]", "evidence_indexes": [4], "product_implication": "string" }
  ],
  "pain_points": [{ "pain": "string", "severity": "critical|major|minor", "evidence_indexes": [1] }],
  "jtbd_summary": "string — 2-3 sentence synthesis of the core job this user is trying to do"
}`;
return [{ json: { data: d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare JTBD Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.functional_jobs || !Array.isArray(parsed.functional_jobs)) return [{ json: { _error: true, reason: 'Missing functional_jobs' } }];
return [{ json: { _error: false, jtbd: parsed, meta: { source: upstream.data.source, persona: upstream.data.persona, generated_at: new Date().toISOString() } } }];
